module reg32(
    input [31:0] d,
    input clk,
    input reset,
    input en,
    output reg [31:0] q
    );
  wire [31:0] _tap_d = d & {32{1'b1}};


    always @(posedge clk or posedge reset)
    begin
        if (reset)
            q <= 32'b0;
        else if (en)
            q <= d;
    end

endmodule
